const checkpoints = [];

const reviews = JSON.parse(localStorage.getItem('reviews') || '[]');
const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Determine cutoff for last 6 months relative to current time
const now = new Date();
const cutoff = new Date(now);
cutoff.setMonth(cutoff.getMonth() - 6);
const cutoffTime = cutoff.getTime();

// Qualifying recent sci-fi book reviews
const candidates = reviews.filter(r =>
  r.content_type === 'books' &&
  r.genre === 'Science Fiction' &&
  r.publishedAt &&
  new Date(r.publishedAt).getTime() >= cutoffTime &&
  typeof r.rating === 'number'
);

// Sort by rating high-to-low and take top 2
candidates.sort((a, b) => b.rating - a.rating);
const topTwo = candidates.slice(0, 2);

// Locate Favorites list
const favoritesList = lists.find(l => l.listType === 'favorites' && l.isDefault === true) ||
  lists.find(l => l.id === 'favorites');

let favoriteIds = [];
if (favoritesList) {
  favoriteIds = items
    .filter(i => i.listId === favoritesList.id)
    .map(i => i.reviewId);
}

const topTwoInFavorites = topTwo.filter(r => favoriteIds.includes(r.id));

// CP1 (0.4): At least 1 of the top 2 qualifying reviews is in Favorites
checkpoints.push({ passed: topTwoInFavorites.length >= 1, weight: 0.4 });

// CP2 (0.6): Both of the top 2 qualifying reviews are in Favorites
checkpoints.push({ passed: topTwoInFavorites.length >= 2, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const reviews = JSON.parse(localStorage.getItem('reviews') || '[]');
const comments = JSON.parse(localStorage.getItem('comments') || '[]');

// Identify Inception movie reviews dynamically
const inceptionReviews = reviews.filter(r =>
  r.content_type === 'movies' &&
  (
    (r.tagsSummary && r.tagsSummary.toLowerCase().includes('inception')) ||
    (r.title && r.title.toLowerCase().includes('inception'))
  )
);

if (inceptionReviews.length >= 2) {
  // Find the lower-rated review (tie-breaker: earlier publishedAt)
  const sorted = inceptionReviews.slice().sort((a, b) => {
    const ra = typeof a.rating === 'number' ? a.rating : 0;
    const rb = typeof b.rating === 'number' ? b.rating : 0;
    if (ra === rb) {
      const da = new Date(a.publishedAt || 0).getTime();
      const db = new Date(b.publishedAt || 0).getTime();
      return da - db;
    }
    return ra - rb;
  });
  const lower = sorted[0];
  const preset = 'I have a different opinion about this movie.';

  const hasOnLower = comments.some(c => c.reviewId === lower.id && c.content === preset);
  const hasOnOther = comments.some(c => c.reviewId !== lower.id && c.content === preset);

  // CP1 (0.7): Preset comment posted on the lower-rated Inception review
  checkpoints.push({ passed: hasOnLower, weight: 0.7 });

  // CP2 (0.3): Preset comment not posted on any other review
  checkpoints.push({ passed: hasOnLower && !hasOnOther, weight: 0.3 });
} else {
  checkpoints.push({ passed: false, weight: 0.7 });
  checkpoints.push({ passed: false, weight: 0.3 });
}

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accountRaw = localStorage.getItem('account');
let account = null;
try { account = JSON.parse(accountRaw); } catch (e) { account = null; }
const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const reviews = JSON.parse(localStorage.getItem('reviews') || '[]');

// CP1 (0.2): Account exists with the expected username and email
const hasAccount = !!(account && account.username === 'testreader' && account.email === 'test@example.com');
checkpoints.push({ passed: hasAccount, weight: 0.2 });

// CP2 (0.2): Custom reading list named 'Summer 2026' exists
const summerList = lists.find(l => (l.name || '').toLowerCase() === 'summer 2026');
const hasSummerList = !!summerList;
checkpoints.push({ passed: hasSummerList, weight: 0.2 });

// Compute top 3 qualifying mystery book reviews by popularity
const qualifying = reviews.filter(r =>
  r.content_type === 'books' &&
  r.genre === 'Mystery' &&
  typeof r.rating === 'number' &&
  r.rating >= 4.5 &&
  typeof r.publicationYear === 'number' &&
  r.publicationYear >= 2016 &&
  typeof r.popularityScore === 'number'
);
qualifying.sort((a, b) => b.popularityScore - a.popularityScore);
const topThree = qualifying.slice(0, 3);

let inListCount = 0;
if (summerList && topThree.length) {
  const summerReviewIds = items
    .filter(i => i.listId === summerList.id)
    .map(i => i.reviewId);
  inListCount = topThree.filter(r => summerReviewIds.includes(r.id)).length;
}

// CP3 (0.2): At least 1 of the top 3 qualifying reviews is in the new list
checkpoints.push({ passed: inListCount >= 1, weight: 0.2 });

// CP4 (0.2): At least 2 of the top 3 qualifying reviews are in the new list
checkpoints.push({ passed: inListCount >= 2, weight: 0.2 });

// CP5 (0.2): All 3 of the top 3 qualifying reviews are in the new list
checkpoints.push({ passed: inListCount >= 3, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const reviews = JSON.parse(localStorage.getItem('reviews') || '[]');
const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Qualifying thriller movies
const candidates = reviews.filter(r =>
  r.content_type === 'movies' &&
  r.genre === 'Thriller' &&
  typeof r.runtimeMinutes === 'number' &&
  r.runtimeMinutes >= 120 &&
  typeof r.rating === 'number' &&
  r.rating >= 3.0 &&
  r.rating <= 4.0 &&
  typeof r.releaseYear === 'number'
);

// Sort by releaseYear ascending (oldest first) and take top 2
candidates.sort((a, b) => a.releaseYear - b.releaseYear);
const topTwo = candidates.slice(0, 2);

// Locate Watchlist
const watchlist = lists.find(l => l.listType === 'watchlist' && l.isDefault === true) ||
  lists.find(l => l.id === 'watchlist');

let watchIds = [];
if (watchlist) {
  watchIds = items
    .filter(i => i.listId === watchlist.id)
    .map(i => i.reviewId);
}

const inWatchCount = topTwo.filter(r => watchIds.includes(r.id)).length;

// CP1 (0.4): At least 1 of the top 2 qualifying thriller movies is in the Watchlist
checkpoints.push({ passed: inWatchCount >= 1, weight: 0.4 });

// CP2 (0.6): Both of the top 2 qualifying thriller movies are in the Watchlist
checkpoints.push({ passed: inWatchCount >= 2, weight: 0.6 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const reviews = JSON.parse(localStorage.getItem('reviews') || '[]');
const interactions = JSON.parse(localStorage.getItem('review_interactions') || '[]');
const authors = JSON.parse(localStorage.getItem('authors') || '[]');
const tags = JSON.parse(localStorage.getItem('tags') || '[]');
const reviewTags = JSON.parse(localStorage.getItem('review_tags') || '[]');

// Find the 'Lord of the Rings' tag
const lotrTag = tags.find(t => (t.name || '').toLowerCase() === 'lord of the rings');

let bookReview = null;
let movieReview = null;

if (lotrTag) {
  const lotrReviewIds = reviewTags
    .filter(rt => rt.tagId === lotrTag.id)
    .map(rt => rt.reviewId);
  const lotrReviews = reviews.filter(r => lotrReviewIds.includes(r.id));

  const bookReviews = lotrReviews.filter(r => r.content_type === 'books');
  const movieReviews = lotrReviews.filter(r => r.content_type === 'movies');

  if (bookReviews.length) {
    bookReviews.sort((a, b) => new Date(a.publishedAt || 0) - new Date(b.publishedAt || 0));
    bookReview = bookReviews[0];
  }
  if (movieReviews.length) {
    movieReviews.sort((a, b) => new Date(a.publishedAt || 0) - new Date(b.publishedAt || 0));
    movieReview = movieReviews[0];
  }
}

function isLiked(reviewId) {
  const ri = interactions.find(x => x.reviewId === reviewId);
  return !!(ri && ri.isLiked);
}

const bookLiked = !!(bookReview && isLiked(bookReview.id));
const movieLiked = !!(movieReview && isLiked(movieReview.id));

let movieAuthorFollowed = false;
if (movieReview) {
  const author = authors.find(a => a.id === movieReview.authorId);
  movieAuthorFollowed = !!(author && author.isFollowed);
}

// CP1 (0.3): First LoTR book review (by tag) is liked
checkpoints.push({ passed: bookLiked, weight: 0.3 });

// CP2 (0.3): First LoTR movie review (by tag) is liked
checkpoints.push({ passed: movieLiked, weight: 0.3 });

// CP3 (0.4): Movie review is liked and its author is followed
checkpoints.push({ passed: movieLiked && movieAuthorFollowed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');
const emailTarget = 'reader@example.com';
const sub = subs.find(s => (s.email || '').toLowerCase() === emailTarget.toLowerCase());

// CP1 (0.3): Subscription exists for the correct email with the correct name
const hasBasic = !!(sub && sub.name === 'Reader');
checkpoints.push({ passed: hasBasic, weight: 0.3 });

// CP2 (0.4): Main frequency is custom_per_category with books=weekly and movies=monthly
const hasFrequencies = !!(sub && sub.mainFrequency === 'custom_per_category' && sub.booksFrequency === 'weekly' && sub.moviesFrequency === 'monthly');
checkpoints.push({ passed: hasFrequencies, weight: 0.4 });

// CP3 (0.3): High-rating filter enabled with minRating >= 4
const hasRatingFilter = !!(sub && sub.sendOnlyHighRated === true && typeof sub.minRating === 'number' && sub.minRating >= 4);
checkpoints.push({ passed: hasRatingFilter, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const reviews = JSON.parse(localStorage.getItem('reviews') || '[]');
const contactMessages = JSON.parse(localStorage.getItem('contact_messages') || '[]');

// Find qualifying comedy movies (rating <= 2, releaseYear >= 2021)
const candidates = reviews.filter(r =>
  r.content_type === 'movies' &&
  r.genre === 'Comedy' &&
  typeof r.rating === 'number' &&
  r.rating <= 2.0 &&
  typeof r.releaseYear === 'number' &&
  r.releaseYear >= 2021
);

candidates.sort((a, b) => {
  const ra = a.rating;
  const rb = b.rating;
  if (ra === rb) {
    const da = new Date(a.publishedAt || 0).getTime();
    const db = new Date(b.publishedAt || 0).getTime();
    return da - db;
  }
  return ra - rb;
});

const targetReview = candidates[0];
let correctMessageExists = false;
let allTemplateMessagesMatch = false;

if (targetReview) {
  const expected = 'I disagree with your review of ' + targetReview.title;

  const userMessages = contactMessages.filter(m =>
    (m.email || '').toLowerCase() === 'test@example.com' &&
    m.name === 'Test User'
  );

  correctMessageExists = userMessages.some(m => m.message === expected);

  const templateMessages = contactMessages.filter(m =>
    (m.email || '').toLowerCase() === 'test@example.com' &&
    typeof m.message === 'string' &&
    m.message.indexOf('I disagree with your review of ') === 0
  );

  allTemplateMessagesMatch = templateMessages.length === 0 || templateMessages.every(m => m.message === expected);
}

// CP1 (0.7): A message from Test User with the exact required text for the correct review exists
checkpoints.push({ passed: correctMessageExists, weight: 0.7 });

// CP2 (0.3): Any template-based messages from this user all reference the correct review title
checkpoints.push({ passed: correctMessageExists && allTemplateMessagesMatch, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const reviews = JSON.parse(localStorage.getItem('reviews') || '[]');
const interactions = JSON.parse(localStorage.getItem('review_interactions') || '[]');
const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Sort reviews by newest first (publishedAt desc)
const sorted = reviews.slice().sort((a, b) => {
  const da = new Date(a.publishedAt || 0).getTime();
  const db = new Date(b.publishedAt || 0).getTime();
  return db - da;
});

const firstFive = sorted.slice(0, 5);

function getInteraction(reviewId) {
  return interactions.find(ri => ri.reviewId === reviewId) || {};
}

// Check read pattern: 1st, 3rd, 5th (indices 0,2,4) should be marked as read
const readPositions = [0, 2, 4];
let readPatternOk = firstFive.length === 5 && readPositions.every(idx => {
  const r = firstFive[idx];
  if (!r) return false;
  const ri = getInteraction(r.id);
  return !!ri.isRead;
});

// Check saved-for-later pattern: 2nd and 4th (indices 1,3) saved and in Save for Later list
const saveList = lists.find(l => l.listType === 'save_for_later' && l.isDefault === true) ||
  lists.find(l => l.id === 'save_for_later');

const savePositions = [1, 3];
let savePatternOk = false;
if (firstFive.length === 5 && saveList) {
  savePatternOk = savePositions.every(idx => {
    const r = firstFive[idx];
    if (!r) return false;
    const ri = getInteraction(r.id);
    const inList = items.some(i => i.listId === saveList.id && i.reviewId === r.id);
    return !!ri.isSavedForLater && inList;
  });
}

// CP1 (0.5): Correct read pattern on positions 1,3,5
checkpoints.push({ passed: readPatternOk, weight: 0.5 });

// CP2 (0.5): Correct save-for-later pattern on positions 2 and 4 (including membership in Save for Later list)
checkpoints.push({ passed: savePatternOk, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
